// Verify an encoded event string by recomputing the canonical checksum.
function checksum(type) {
  const sum = [...type].reduce((a, c) => a + c.charCodeAt(0), 0);
  return String(sum % 97).padStart(2, "0");
}
function verify(encoded) {
  const hash = encoded.lastIndexOf("#");
  if (hash === -1) return false;
  const type = encoded.slice(0, hash);
  const cc = encoded.slice(hash + 1);
  return checksum(type) === cc;
}
module.exports = { verify };
